(176, 'xts-theme_settings_default-css-data', '@font-face {\n	font-weight: normal;\n	font-style: normal;\n	font-family: \"woodmart-font\";\n	src: url(\"//isogift.local/wp-content/themes/woodmart/fonts/woodmart-font-1-400.woff2?v=7.5.2\") format(\"woff2\");\n}\n\n:root {\n	--wd-text-font: \"Inter\", Arial, Helvetica, sans-serif;\n	--wd-text-font-weight: 400;\n	--wd-text-color: rgb(51,51,51);\n	--wd-text-font-size: 16px;\n	--wd-title-font: \"Inter\", Arial, Helvetica, sans-serif;\n	--wd-title-font-weight: 600;\n	--wd-title-color: rgb(51,51,51);\n	--wd-entities-title-font: \"Inter\", Arial, Helvetica, sans-serif;\n	--wd-entities-title-font-weight: 500;\n	--wd-entities-title-transform: inherit;\n	--wd-entities-title-color: #333333;\n	--wd-entities-title-color-hover: rgb(178, 138, 62);\n	--wd-alternative-font: \"Inter\", Arial, Helvetica, sans-serif;\n	--wd-widget-title-font: \"Be Vietnam Pro\", Arial, Helvetica, sans-serif;\n	--wd-widget-title-font-weight: 600;\n	--wd-widget-title-transform: uppercase;\n	--wd-widget-title-color: #333;\n	--wd-widget-title-font-size: 16px;\n	--wd-header-el-font: \"Be Vietnam Pro\", Arial, Helvetica, sans-serif;\n	--wd-header-el-font-weight: 700;\n	--wd-header-el-transform: inherit;\n	--wd-header-el-font-size: 18px;\n	--wd-primary-color: rgb(0,47,117);\n	--wd-alternative-color: rgb(178,138,62);\n	--wd-link-color: rgb(0,47,117);\n	--wd-link-color-hover: rgb(178,138,62);\n	--btn-default-font-family: \"Inter\", Arial, Helvetica, sans-serif;\n	--btn-default-font-weight: 500;\n	--btn-default-transform: inherit;\n	--btn-default-bgcolor: rgb(0,47,117);\n	--btn-default-bgcolor-hover: rgb(199,146,77);\n	--btn-accented-font-family: \"Inter\", Arial, Helvetica, sans-serif;\n	--btn-accented-font-weight: 400;\n	--btn-accented-transform: inherit;\n	--btn-accented-bgcolor: rgb(0,47,117);\n	--btn-accented-bgcolor-hover: rgb(199,146,77);\n	--wd-form-brd-width: 2px;\n	--notices-success-bg: #459647;\n	--notices-success-color: #fff;\n	--notices-warning-bg: #E0B252;\n	--notices-warning-color: #fff;\n}\n.woodmart-woocommerce-layered-nav .wd-scroll-content {\n	max-height: 223px;\n}\n.wd-popup.wd-age-verify {\n	--wd-popup-width: 500px;\n}\n.wd-popup.wd-promo-popup {\n	background-color: #111111;\n	background-image: none;\n	background-repeat: no-repeat;\n	background-size: contain;\n	background-position: left center;\n	--wd-popup-width: 800px;\n}\n.page-title-default {\n	background-color: #0a0a0a;\n	background-image: none;\n	background-size: cover;\n	background-position: center center;\n}\n.footer-container {\n	background-color: #ffffff;\n	background-image: none;\n}\n.wd-nav-arrows.wd-pos-sep:not(:where(.wd-custom-style)) {\n	--wd-arrow-size: 50px;\n	--wd-arrow-icon-size: 22px;\n	--wd-arrow-color: rgb(255,255,255);\n	--wd-arrow-color-hover: rgb(0,47,117);\n	--wd-arrow-bg: rgb(0,47,117);\n	--wd-arrow-bg-hover: rgb(178,138,62);\n}\n.wd-nav-pagin-wrap:not(.wd-custom-style) {\n	--wd-pagin-size: 24px;\n	--wd-pagin-bg: rgb(0,47,117);\n	--wd-pagin-bg-hover: rgb(178,138,62);\n}\n.wd-nav-scroll {\n	--wd-nscroll-height: 16px;\n	--wd-nscroll-width: 25%;\n	--wd-nscroll-bg: rgb(0,47,117);\n	--wd-nscroll-drag-bg: rgb(178,138,62);\n}\n.wd-popup.popup-quick-view {\n	--wd-popup-width: 920px;\n}\n:root{\n--wd-container-w: 1222px;\n--wd-form-brd-radius: 0px;\n--btn-default-color: #333;\n--btn-default-color-hover: #333;\n--btn-accented-color: #fff;\n--btn-accented-color-hover: #fff;\n--btn-default-brd-radius: 5px;\n--btn-default-box-shadow: none;\n--btn-default-box-shadow-hover: none;\n--btn-accented-brd-radius: 5px;\n--btn-accented-box-shadow: none;\n--btn-accented-box-shadow-hover: none;\n--wd-brd-radius: 0px;\n}\n\n@media (min-width: 1239px) {\n.platform-Windows .wd-section-stretch > .elementor-container {\nmargin-left: auto;\nmargin-right: auto;\n}\n}\n\n@media (min-width: 1222px) {\nhtml:not(.platform-Windows) .wd-section-stretch > .elementor-container {\nmargin-left: auto;\nmargin-right: auto;\n}\n}\n\n\n', 'auto'),
